  console.log(`Server started on port ${port}`);
});

package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"log"
	"os"
	"os/exec"
	"path/filepath"

	"github.com/gofiber/fiber/v2"
)

// CompilationResponse represents the response from the compilation endpoint
type CompilationResponse struct {
	HasError    bool   `json:"hasError"`
	CompilerError string `json:"compilerError"`
}

// CompileRequest represents the request to the compilation endpoint
type CompileRequest struct {
	FileName   string `json:"fileName"`
	FileContent string `json:"fileContent"`
}

func main() {
	app := fiber.New()

	app.Post("/compile", func(c *fiber.Ctx) error {
		var request CompileRequest
		if err := c.BodyParser(&request); err != nil {
			return c.Status(400).JSON(CompilationResponse{
				HasError:    true,
				CompilerError: "Invalid request body",
			})
		}

		tmpDir, err := os.MkdirTemp("", "compile")
		if err != nil {
			return c.Status(500).JSON(CompilationResponse{
				HasError:    true,
				CompilerError: "Failed to create temporary directory",
			})
		}
		defer os.RemoveAll(tmpDir)

		filePath := filepath.Join(tmpDir, request.FileName)
		if err := os.WriteFile(filePath, []byte(request.FileContent), 0644); err != nil {
			return c.Status(500).JSON(CompilationResponse{
				HasError:    true,
				CompilerError: "Failed to write file to temporary directory",
			})
		}

		var compiler string
		if filepath.Ext(request.FileName) == ".ts" {
			compiler = "tsc"
		} else if filepath.Ext(request.FileName) == ".cpp" {
			compiler = "g++"
		} else {
			return c.Status(400).JSON(CompilationResponse{
				HasError:    true,
				CompilerError: "Unsupported file extension",
			})
		}

		cmd := exec.Command(compiler, filePath)
		var out bytes.Buffer
		var stderr bytes.Buffer
		cmd.Stdout = &out
		cmd.Stderr = &stderr
		if err := cmd.Run(); err != nil {
			return c.Status(200).JSON(CompilationResponse{
				HasError:    true,
				CompilerError: stderr.String(),
			})
		}

		return c.Status(200).JSON(CompilationResponse{
			HasError:    false,
			CompilerError: "",
		})
	})

	if err := app.Listen(":5000"); err != nil {
		log.Fatal(err)
	}
}

package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"log"
	"os"
	"os/exec"
	"path/filepath"

	"github.com/gofiber/fiber/v2"
)

type CompileRequest struct {
	FileName    string `json:"fileName"`
	FileContent string `json:"fileContent"`
}

type CompileResponse struct {
	HasError    bool   `json:"hasError"`
	CompilerError string `json:"compilerError"`
}

func compileCpp(code string) (bool, string) {
	tmpDir := os.TempDir()
	fileName := filepath.Join(tmpDir, "main.cpp")
	err := os.WriteFile(fileName, []byte(code), 0644)
	if err!= nil {
		return true, err.Error()
	}
	defer os.Remove(fileName)

	cmd := exec.Command("g++", "-o", filepath.Join(tmpDir, "main"), fileName)
	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr
	err = cmd.Run()
	if err!= nil {
		return true, stderr.String()
	}
	return false, ""
}

func compileTs(code string) (bool, string) {
	tmpDir := os.TempDir()
	fileName := filepath.Join(tmpDir, "main.ts")
	err := os.WriteFile(fileName, []byte(code), 0644)
	if err!= nil {
		return true, err.Error()
	}
	defer os.Remove(fileName)

	cmd := exec.Command("tsc", fileName)
	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr
	err = cmd.Run()
	if err!= nil {
		return true, stderr.String()
	}
	return false, ""
}

func main() {
	app := fiber.New()

	app.Post("/compile", func(c *fiber.Ctx) error {
		var request CompileRequest
		err := c.BodyParser(&request)
		if err!= nil {
			return c.Status(400).JSON(fiber.Map{"error": "invalid request"})
		}

		var hasError bool
		var compilerError string
		switch filepath.Ext(request.FileName) {
		case ".cpp":
			hasError, compilerError = compileCpp(request.FileContent)
		case ".ts":
			hasError, compilerError = compileTs(request.FileContent)
		default:
			return c.Status(400).JSON(fiber.Map{"error": "unsupported file extension"})
		}

		return c.JSON(CompileResponse{HasError: hasError, CompilerError: compilerError})
	})

	log.Fatal(app.Listen(":5000"))
}

const express = require('express');
const multer = require('multer');
const { v4: uuidv4 } = require('uuid');
const childProcess = require('child_process');
const fs = require('fs');
const path = require('path');

const app = express();
app.use(express.json());

const compileCode = (fileName, fileContent) => {
    const tempDir = `temp-${uuidv4()}`;
    fs.mkdirSync(tempDir);
    fs.writeFileSync(path.join(tempDir, fileName), fileContent);

    let compilerError = null;
    let hasError = false;

    if (fileName.endsWith('.ts')) {
        try {
            childProcess.execSync(`tsc ${path.join(tempDir, fileName)}`, { stdio: 'pipe' });
        } catch (error) {
            compilerError = error.stdout.toString();
            hasError = true;
        }
    } else if (fileName.endsWith('.cpp')) {
        try {
            childProcess.execSync(`g++ ${path.join(tempDir, fileName)} -o ${path.join(tempDir, 'output')}`, { stdio: 'pipe' });
        } catch (error) {
            compilerError = error.stdout.toString();
            hasError = true;
        }
    }

    fs.rmdirSync(tempDir, { recursive: true });

    return { hasError, compilerError };
};

app.post('/compile', (req, res) => {
    const { fileName, fileContent } = req.body;
    if (!fileName || !fileContent) {
        return res.status(400).json({ error: 'Missing file name or content' });
    }

    const { hasError, compilerError } = compileCode(fileName, fileContent);
    res.json({ hasError, compilerError });
});

app.listen(5000, '0.0.0.0', () => {
    console.log('Server listening on port 5000');
});

const express = require('express');
const multer = require('multer');
const { spawn } = require('child_process');
const fs = require('fs');
const path = require('path');

const app = express();
const port = 5000;

app.use(express.json());

const compileCpp = (fileName, fileContent) => {
    return new Promise((resolve, reject) => {
        fs.writeFileSync(fileName, fileContent);
        const compiler = spawn('g++', [fileName, '-o', 'output']);
        let error = '';
        compiler.stderr.on('data', (data) => {
            error += data.toString();
        });
        compiler.on('close', (code) => {
            if (code === 0) {
                resolve(null);
            } else {
                resolve(error);
            }
        });
    });
};

const compileTs = (fileName, fileContent) => {
    return new Promise((resolve, reject) => {
        fs.writeFileSync(fileName, fileContent);
        const compiler = spawn('tsc', [fileName]);
        let error = '';
        compiler.stderr.on('data', (data) => {
            error += data.toString();
        });
        compiler.on('close', (code) => {
            if (code === 0) {
                resolve(null);
            } else {
                resolve(error);
            }
        });
    });
};

app.post('/compile', async (req, res) => {
    const { fileName, fileContent } = req.body;
    let compilerError = null;
    let hasError = false;

    if (fileName.endsWith('.cpp')) {
        compilerError = await compileCpp(fileName, fileContent);
    } else if (fileName.endsWith('.ts')) {
        compilerError = await compileTs(fileName, fileContent);
    } else {
        res.status(400).send({ message: 'Unsupported file type' });
        return;
    }

    if (compilerError) {
        hasError = true;
    }

    res.send({ hasError, compilerError });
});

app.listen(port, '0.0.0.0', () => {
    console.log(`Server started on port ${port}`);
});

from flask import Flask, request, jsonify
import subprocess
import os

app = Flask(__name__)

def compile_cpp(file_name, file_content):
    with open(file_name, 'w') as f:
        f.write(file_content)
    try:
        output = subprocess.check_output(['g++', file_name], stderr=subprocess.STDOUT)
        os.remove(file_name)
        return False, None
    except subprocess.CalledProcessError as e:
        error = e.output.decode('utf-8')
        os.remove(file_name)
        return True, error

def compile_ts(file_name, file_content):
    with open(file_name, 'w') as f:
        f.write(file_content)
    try:
        output = subprocess.check_output(['tsc', file_name], stderr=subprocess.STDOUT)
        os.remove(file_name)
        return False, None
    except subprocess.CalledProcessError as e:
        error = e.output.decode('utf-8')
        os.remove(file_name)
        return True, error

@app.route('/compile', methods=['POST'])
def compile():
    data = request.get_json()
    file_name = data['fileName']
    file_content = data['fileContent']
    if file_name.endswith('.cpp'):
        has_error, compiler_error = compile_cpp(file_name, file_content)
    elif file_name.endswith('.ts'):
        has_error, compiler_error = compile_ts(file_name, file_content)
    else:
