	SearchFilename string `json:"search_filename"`
	SearchDir string `json:"search_dir"`
}

// Response represents the response for the /search endpoint
type Response struct {
	Files []string `json:"files"`
}

func main() {
	app := fiber.New()

	app.Post("/search", func(c *fiber.Ctx) error {
		var requestBody RequestBody
		if err := c.BodyParser(&requestBody); err != nil {
			return c.Status(400).JSON(fiber.Map{"error": "Invalid request body"})
		}

		files := make([]string, 0)

		// Get the absolute path of the search directory
		searchDir := filepath.Join("/data", requestBody.SearchDir)

		// Check if the search directory exists
		if _, err := os.Stat(searchDir); os.IsNotExist(err) {
			return c.Status(400).JSON(fiber.Map{"error": "Search directory does not exist"})
		}

		// Walk through the search directory
		err := filepath.WalkDir(searchDir, func(path string, dirEntry os.DirEntry, err error) error {
			if err != nil {
				return err
			}

			// Check if the current entry is a file
			if !dirEntry.IsDir() {
				// Check if the file matches the search filename
				if requestBody.SearchFilename != "" && strings.HasPrefix(dirEntry.Name(), requestBody.SearchFilename) {
					files = append(files, path)
				} else if requestBody.SearchContent != "" {
					// Read the file content
					content, err := ioutil.ReadFile(path)
					if err != nil {
						return err
					}

					// Check if the file content contains the search content
					if strings.Contains(string(content), requestBody.SearchContent) {
						files = append(files, path)
					}
				}
			}

			return nil
		})

		if err != nil {
			return c.Status(500).JSON(fiber.Map{"error": "Internal server error"})
		}

		return c.JSON(Response{Files: files})
	})

	log.Fatal(app.Listen(":5000"))
}

const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
const port = 5000;

app.use(express.json());

// Define the data directory
const dataDirectory = '/data';

// Function to search for files
function searchFiles(searchContent, searchFilename, searchDir) {
    const files = [];
    const directory = path.join(dataDirectory, searchDir || '');
    fs.readdirSync(directory).forEach(file => {
        const filePath = path.join(directory, file);
        const stats = fs.statSync(filePath);
        if (stats.isDirectory()) {
            // Recursively search subdirectories
            files.push(...searchFiles(searchContent, searchFilename, path.join(searchDir || '', file)));
        } else {
            // Check if the file matches the search criteria
            if ((searchContent && fs.readFileSync(filePath, 'utf8').includes(searchContent)) ||
                (searchFilename && file.startsWith(searchFilename))) {
                files.push(filePath);
            }
        }
    });
    return files;
}

// Define the API endpoint
app.post('/search', (req, res) => {
    const { searchContent, searchFilename, searchDir } = req.body;
    if (!searchContent && !searchFilename) {
        res.status(400).send({ error: 'Invalid input: searchContent or searchFilename is required' });
        return;
    }
    try {
        const files = searchFiles(searchContent, searchFilename, searchDir);
        res.send({ files });
    } catch (error) {
        console.error(error);
        res.status(500).send({ error: 'Internal Server Error' });
    }
});

// Start the server
app.listen(port, '0.0.0.0', () => {
    console.log(`Server started on port ${port}`);
});

import os
import json
from flask import Flask, request, jsonify

app = Flask(__name__)

# Define the data directory
DATA_DIR = '/data'

# Function to search for files
def search_files(search_content, search_filename, search_dir):
    files = []
    # If search_dir is not provided, use the root data directory
    if search_dir is None:
        search_dir = DATA_DIR
    else:
        # If search_dir is provided, append it to the root data directory
        search_dir = os.path.join(DATA_DIR, search_dir.lstrip('/'))

    # Walk through the directory and its subdirectories
    for root, dirs, filenames in os.walk(search_dir):
        for filename in filenames:
            file_path = os.path.join(root, filename)
            # Check if the file matches the filename
            if search_filename is not None and filename.startswith(search_filename):
                files.append(file_path)
            # Check if the file contains the specified content
            elif search_content is not None:
                try:
                    with open(file_path, 'r') as file:
                        content = file.read()
                        if search_content in content:
                            files.append(file_path)
                except Exception as e:
                    print(f"Error reading file {file_path}: {e}")

    return files

# Define the API endpoint
@app.route('/search', methods=['POST'])
def search():
    data = request.get_json()
    search_content = data.get('search_content')
    search_filename = data.get('search_filename')
    search_dir = data.get('search_dir')

    # Validate the input
    if search_content is None and search_filename is None:
        return jsonify({'error': 'Either search_content or search_filename must be provided'}), 400

    files = search_files(search_content, search_filename, search_dir)
    return jsonify({'files': files})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

