    sql_create_profiles_table = """CREATE TABLE IF NOT EXISTS profiles (
                                    username text PRIMARY KEY,
                                    profile_page text NOT NULL,
                                    profile_photo blob NOT NULL
                                );"""
    try:
        c = conn.cursor()
        c.execute(sql_create_profiles_table)
    except Error as e:
        print(e)

# Create a new profile
def create_profile(conn, profile):
    sql = ''' INSERT INTO profiles(username, profile_page, profile_photo)
              VALUES(?,?,?) '''
    try:
        c = conn.cursor()
        c.execute(sql, profile)
        conn.commit()
        return True
    except Error as e:
        print(e)
        return False

# Get a profile
def get_profile(conn, username):
    sql = ''' SELECT profile_page FROM profiles
              WHERE username = ?'''
    try:
        c = conn.cursor()
        c.execute(sql, (username,))
        rows = c.fetchall()
        if len(rows) > 0:
            return rows[0][0]
        else:
            return None
    except Error as e:
        print(e)
        return None

# Get a profile photo
def get_profile_photo(conn, username):
    sql = ''' SELECT profile_photo FROM profiles
              WHERE username = ?'''
    try:
        c = conn.cursor()
        c.execute(sql, (username,))
        rows = c.fetchall()
        if len(rows) > 0:
            return rows[0][0]
        else:
            return None
    except Error as e:
