# Check if a profile exists
def profile_exists(conn, username):
    sql = ''' SELECT * FROM profiles
              WHERE username = ?'''
    try:
        c = conn.cursor()
        c.execute(sql, (username,))
        rows = c.fetchall()
        if len(rows) > 0:
            return True
        else:
            return False
    except Error as e:
