		if err != nil {
			return c.Status(http.StatusInternalServerError).SendString("Server error")
		}

		return c.Status(http.StatusCreated).SendString("Comment added successfully")
	})

	// Rate a recipe
	app.Post("/recipes/:recipeId/ratings", func(c *fiber.Ctx) error {
