package main

import (
    "bytes"
    "encoding/json"
    "errors"
    "io/ioutil"
    "log"
    "os"
    "path/filepath"
    "regexp"
    "strings"

    "github.com/gofiber/fiber/v2"
)

// ErrorResponse represents an error response
type ErrorResponse struct {
    Error string `json:"error"`
}

// SearchResponse represents a search response
type SearchResponse struct {
    Files []string `json:"files"`
}

func main() {
    app := fiber.New()

    // Define the search endpoint
    app.Get("/search", func(c *fiber.Ctx) error {
        // Get query parameters
        regex := c.Query("regex")
        directory := c.Query("directory", "./files")
        recursive := c.Query("recursive", "false") == "true"

        // Validate regex
        _, err := regexp.Compile(regex)
        if err != nil {
            return c.Status(400).JSON(ErrorResponse{Error: "Invalid regex: " + err.Error()})
        }

        // Search files
        files, err := searchFiles(directory, regex, recursive)
        if err != nil {
            return c.Status(500).JSON(ErrorResponse{Error: "Internal server error: " + err.Error()})
        }

        // Return search results
        return c.JSON(SearchResponse{Files: files})
    })

    // Start the server
    log.Fatal(app.Listen(":5000"))
}

// searchFiles searches files in the given directory and returns files whose content matches the given regex
func searchFiles(directory, regex string, recursive bool) ([]string, error) {
    // Compile the regex
    re, err := regexp.Compile(regex)
    if err != nil {
        return nil, err
    }

    // Initialize the list of matching files
    var files []string

    // Walk the directory
    err = filepath.WalkDir(directory, func(path string, dirEntry os.DirEntry, err error) error {
        if err != nil {
            return err
        }

        // Check if the entry is a file
        if !dirEntry.IsDir() {
            // Read the file content
            content, err := ioutil.ReadFile(path)
            if err != nil {
                return err
            }

            // Check if the file content matches the regex
            if re.Find(content) != nil {
                // Add the file to the list of matching files
                files = append(files, strings.TrimPrefix(path, directory))
            }
        }

        // If not recursive, skip subdirectories
        if !recursive && dirEntry.IsDir() {
            return filepath.SkipDir
        }

        return nil
    })

    return files, err
}

package main

import (
	"bufio"
	"encoding/json"
	"fmt"
	"io/fs"
	"log"
	"os"
	"path/filepath"
	"regexp"
	"strings"

	"github.com/gofiber/fiber/v2"
)

type ErrorResponse struct {
	Error string `json:"error"`
}

type SearchResponse struct {
	Files []string `json:"files"`
}

func main() {
	app := fiber.New()

	app.Get("/search", func(c *fiber.Ctx) error {
		regexStr := c.Query("regex")
		directory := c.Query("directory", "./files")
		recursive := c.Query("recursive", "false") == "true"

		if !strings.HasPrefix(directory, "./files") {
			return c.Status(400).JSON(ErrorResponse{Error: "Invalid directory"})
		}

		regex, err := regexp.Compile(regexStr)
		if err != nil {
			return c.Status(400).JSON(ErrorResponse{Error: "Invalid regex"})
		}

		files := make([]string, 0)
		err = filepath.WalkDir(directory, func(path string, dir fs.DirEntry, err error) error {
			if err != nil {
				return err
			}

			if !recursive && dir.IsDir() && path != directory {
				return fs.SkipDir
			}

			if !dir.IsDir() {
				filePath := path
				if !strings.HasPrefix(filePath, directory) {
					filePath = strings.TrimPrefix(filePath, "./files/")
				}

				file, err := os.Open(path)
				if err != nil {
					return err
				}
				defer file.Close()

				scanner := bufio.NewScanner(file)
				for scanner.Scan() {
					if regex.MatchString(scanner.Text()) {
						files = append(files, filePath)
						break
					}
				}

				if err := scanner.Err(); err != nil {
					return err
				}
			}

			return nil
		})

		if err != nil {
			return c.Status(500).JSON(ErrorResponse{Error: "Internal server error"})
		}

		return c.JSON(SearchResponse{Files: files})
	})

	log.Fatal(app.Listen(":5000"))
}

const express = require('express');
const fs = require('fs');
const path = require('path');
const app = express();
const port = 5000;

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

app.get('/search', (req, res) => {
    const regex = req.query.regex;
    const directory = req.query.directory || '';
    const recursive = req.query.recursive === 'true';

    if (!regex) {
        return res.status(400).json({ error: 'Regex is required' });
    }

    try {
        const regexPattern = new RegExp(regex);
    } catch (error) {
        return res.status(400).json({ error: 'Invalid regex pattern' });
    }

    const filesRoot = path.join(__dirname, 'files');
    const searchDirectory = path.join(filesRoot, directory);

    if (!fs.existsSync(searchDirectory)) {
        return res.status(400).json({ error: 'Directory does not exist' });
    }

    const matchingFiles = [];

    function searchFiles(dir) {
        const files = fs.readdirSync(dir);
        for (const file of files) {
            const filePath = path.join(dir, file);
            const stats = fs.statSync(filePath);

            if (stats.isDirectory()) {
                if (recursive) {
                    searchFiles(filePath);
                }
            } else {
                try {
                    const fileContent = fs.readFileSync(filePath, 'utf8');
                    if (regexPattern.test(fileContent)) {
                        const relativePath = path.relative(searchDirectory, filePath);
                        matchingFiles.push(relativePath);
                    }
                } catch (error) {
                    console.error(`Error reading file ${filePath}: ${error}`);
                }
            }
        }
    }

    searchFiles(searchDirectory);

    res.json({ files: matchingFiles });
});

app.use((error, req, res, next) => {
    console.error(error);
    res.status(500).json({ error: 'Internal server error' });
});

app.listen(port, '0.0.0.0', () => {
    console.log(`Server listening on port ${port}`);
});

