			err = rows.Scan(&entry.ID, &entry.Title, &entry.Content, &entry.LastModifiedBy, &lastModifiedAt)
			if err != nil {
				return err
			}
			entry.LastModifiedAt, err = time.Parse("2006-01-02 15:04:05", lastModifiedAt)
			if err != nil {
				return err
			}
			entries = append(entries, entry)
		}

		return c.JSON(entries)
	})

	// Create a new entry
	app.Post("/entries", func(c *fiber.Ctx) error {
		var newEntry NewEntry
		err := json.Unmarshal(c.Body(), &newEntry)
		if err != nil {
			return err
		}

		id := fmt.Sprintf("%x", time.Now().UnixNano())
		_, err = db.Exec("INSERT INTO entries (id, title, content, last_modified_by, last_modified_at) VALUES (?, ?, ?, ?, ?)",
			id, newEntry.Title, newEntry.Content, newEntry.CreatedBy, time.Now().Format("2006-01-02 15:04:05"))
		if err != nil {
			return err
		}

		return c.Status(http.StatusCreated).JSON(Entry{
			ID:          id,
			Title:       newEntry.Title,
			Content:     newEntry.Content,
			LastModifiedBy: newEntry.CreatedBy,
			LastModifiedAt: time.Now(),
		})
	})

	// Get a specific entry
	app.Get("/entries/:entryId", func(c *fiber.Ctx) error {
		entryID := c.Params("entryId")

		var entry Entry
		var lastModifiedAt string
		err := db.QueryRow("SELECT id, title, content, last_modified_by, last_modified_at FROM entries WHERE id = ?", entryID).
			Scan(&entry.ID, &entry.Title, &entry.Content, &entry.LastModifiedBy, &lastModifiedAt)
		if err != nil {
			if err == sql.ErrNoRows {
				return c.Status(http.StatusNotFound).SendString("Entry not found")
			}
			return err
		}

		entry.LastModifiedAt, err = time.Parse("2006-01-02 15:04:05", lastModifiedAt)
		if err != nil {
			return err
		}

		return c.JSON(entry)
	})

	// Update an existing entry
	app.Put("/entries/:entryId", func(c *fiber.Ctx) error {
		entryID := c.Params("entryId")

		var updateEntry UpdateEntry
		err := json.Unmarshal(c.Body(), &updateEntry)
		if err != nil {
			return err
		}

		// Check if entry exists
		var count int
		err = db.QueryRow("SELECT COUNT(*) FROM entries WHERE id = ?", entryID).Scan(&count)
		if err != nil {
			return err
		}
		if count == 0 {
			return c.Status(http.StatusNotFound).SendString("Entry not found")
		}

		// Create a new edit
		editID := fmt.Sprintf("%x", time.Now().UnixNano())
		_, err = db.Exec("INSERT INTO edits (id, entry_id, modified_by, summary, content, created_at) VALUES (?, ?, ?, ?, ?, ?)",
			editID, entryID, updateEntry.ModifiedBy, updateEntry.Summary, updateEntry.Content, time.Now().Format("2006-01-02 15:04:05"))
		if err != nil {
			return err
		}

		// Update the entry
		_, err = db.Exec("UPDATE entries SET content = ?, last_modified_by = ?, last_modified_at = ? WHERE id = ?",
			updateEntry.Content, updateEntry.ModifiedBy, time.Now().Format("2006-01-02 15:04:05"), entryID)
		if err != nil {
			return err
		}

		return c.JSON(Entry{
			ID:          entryID,
			Title:       "", // Title is not updated
			Content:     updateEntry.Content,
			LastModifiedBy: updateEntry.ModifiedBy,
			LastModifiedAt: time.Now(),
		})
	})

	// Get the history of edits for a specific entry
	app.Get("/entries/:entryId/edits", func(c *fiber.Ctx) error {
		entryID := c.Params("entryId")

		rows, err := db.Query("SELECT id, entry_id, modified_by, summary, content, created_at FROM edits WHERE entry_id = ?", entryID)
		if err != nil {
			return err
		}
		defer rows.Close()

		var edits []Edit
		for rows.Next() {
			var edit Edit
			var createdAt string
			err = rows.Scan(&edit.ID, &edit.EntryID, &edit.ModifiedBy, &edit.Summary, &edit.Content, &createdAt)
			if err != nil {
				return err
			}
			edit.CreatedAt, err = time.Parse("2006-01-02 15:04:05", createdAt)
			if err != nil {
				return err
			}
			edits = append(edits, edit)
		}

		return c.JSON(edits)
	})

	log.Fatal(app.Listen(":5000"))
}

const express = require('express');
const sqlite3 = require('sqlite3').verbose();
const uuid = require('uuid');
const bcrypt = require('bcrypt');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Connect to SQLite database
let db = new sqlite3.Database('./db.sqlite3', (err) => {
  if (err) {
    console.error(err.message);
  }
  console.log('Connected to the database.');
});

// Create tables if they don't exist
db.serialize(function () {
  db.run(`
    CREATE TABLE IF NOT EXISTS entries
    (
      id TEXT PRIMARY KEY,
      title TEXT NOT NULL,
      content TEXT NOT NULL,
      lastModifiedBy TEXT,
      lastModifiedAt TEXT
    );
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS edits
    (
      id TEXT PRIMARY KEY,
      entryId TEXT NOT NULL,
      modifiedBy TEXT NOT NULL,
      summary TEXT NOT NULL,
      content TEXT NOT NULL,
      createdAt TEXT NOT NULL,
      FOREIGN KEY (entryId) REFERENCES entries (id)
    );
  `);
});

// Get all entries
app.get('/entries', (req, res) => {
  db.all('SELECT id, title FROM entries', (err, rows) => {
    if (err) {
      console.error(err.message);
      res.status(500).send('Error fetching entries');
    } else {
      res.send(rows.map((row) => ({ id: row.id, title: row.title, link: `/entries/${row.id}` })));
    }
  });
});

// Create a new entry
app.post('/entries', (req, res) => {
  const { title, content, createdBy } = req.body;
  if (!title || !content || !createdBy) {
    res.status(400).send('Title, content, and createdBy are required');
    return;
  }

  const id = uuid.v4();
  const query = `
    INSERT INTO entries (id, title, content, lastModifiedBy, lastModifiedAt)
    VALUES (?, ?, ?, ?, datetime('now'))
  `;
  db.run(query, [id, title, content, createdBy], (err) => {
    if (err) {
      console.error(err.message);
      res.status(500).send('Error creating entry');
    } else {
      res.status(201).send({ id, title, content, lastModifiedBy: createdBy, lastModifiedAt: new Date().toISOString() });
    }
  });
});

// Get a specific entry
app.get('/entries/:entryId', (req, res) => {
  const entryId = req.params.entryId;
  const query = `
    SELECT * FROM entries
    WHERE id = ?
  `;
  db.get(query, [entryId], (err, row) => {
    if (err) {
      console.error(err.message);
      res.status(500).send('Error fetching entry');
    } else if (!row) {
      res.status(404).send('Entry not found');
    } else {
      res.send(row);
    }
  });
});

// Update an existing entry
app.put('/entries/:entryId', (req, res) => {
  const entryId = req.params.entryId;
  const { content, modifiedBy, summary } = req.body;
  if (!content || !modifiedBy || !summary) {
    res.status(400).send('Content, modifiedBy, and summary are required');
    return;
  }

  const query = `
    SELECT * FROM entries
    WHERE id = ?
  `;
  db.get(query, [entryId], (err, row) => {
    if (err) {
      console.error(err.message);
      res.status(500).send('Error fetching entry');
    } else if (!row) {
      res.status(404).send('Entry not found');
    } else {
      const editId = uuid.v4();
      const editQuery = `
        INSERT INTO edits (id, entryId, modifiedBy, summary, content, createdAt)
        VALUES (?, ?, ?, ?, ?, datetime('now'))
      `;
      db.run(editQuery, [editId, entryId, modifiedBy, summary, content], (err) => {
        if (err) {
          console.error(err.message);
          res.status(500).send('Error creating edit');
        } else {
          const updateQuery = `
            UPDATE entries
            SET content = ?, lastModifiedBy = ?, lastModifiedAt = datetime('now')
            WHERE id = ?
          `;
          db.run(updateQuery, [content, modifiedBy, entryId], (err) => {
            if (err) {
              console.error(err.message);
              res.status(500).send('Error updating entry');
            } else {
              res.send({ id: entryId, title: row.title, content, lastModifiedBy: modifiedBy, lastModifiedAt: new Date().toISOString() });
            }
          });
        }
      });
    }
  });
});

// View the history of edits for a specific entry
app.get('/entries/:entryId/edits', (req, res) => {
  const entryId = req.params.entryId;
  const query = `
    SELECT * FROM edits
    WHERE entryId = ?
  `;
  db.all(query, [entryId], (err, rows) => {
    if (err) {
      console.error(err.message);
      res.status(500).send('Error fetching edits');
    } else if (!rows) {
      res.status(404).send('Entry not found');
    } else {
      res.send(rows);
    }
  });
});

// Start the server
const port = 5000;
app.listen(port, '0.0.0.0', () => {
  console.log(`Server started on port ${port}`);
});

package main

import (
	"archive/zip"
	"bytes"
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
	"path/filepath"

	"github.com/gofiber/fiber/v2"
)

func main() {
	app := fiber.New()

	app.Post("/convert", func(c *fiber.Ctx) error {
		// Read the zip file from the request body
		file, err := c.FormFile("file")
		if err != nil {
			return c.Status(http.StatusBadRequest).SendString("Invalid input")
		}

		// Create a temporary directory to extract the zip file
		tmpDir, err := os.MkdirTemp("", "zip-to-txt")
		if err != nil {
			return c.Status(http.StatusInternalServerError).SendString("Failed to create temporary directory")
		}
		defer os.RemoveAll(tmpDir)

		// Save the zip file to the temporary directory
		tmpFile, err := os.Create(filepath.Join(tmpDir, file.Filename))
		if err != nil {
			return c.Status(http.StatusInternalServerError).SendString("Failed to save zip file")
		}
		defer tmpFile.Close()

		// Copy the zip file from the request body to the temporary file
		_, err = io.Copy(tmpFile, file)
		if err != nil {
			return c.Status(http.StatusInternalServerError).SendString("Failed to copy zip file")
		}

		// Open the zip file
		r, err := zip.OpenReader(tmpFile.Name())
		if err != nil {
			return c.Status(http.StatusInternalServerError).SendString("Failed to open zip file")
		}
		defer r.Close()

		// Initialize a buffer to store the concatenated text
		var text bytes.Buffer

		// Iterate over the files in the zip file
		for _, f := range r.File {
			// Check if the file is a text file
			if filepath.Ext(f.Name) == ".txt" {
				// Open the file
				rc, err := f.Open()
				if err != nil {
					return c.Status(http.StatusInternalServerError).SendString("Failed to open file in zip")
				}
				defer rc.Close()

				// Read the file contents
				buf := make([]byte, 1024)
				for {
					n, err := rc.Read(buf)
					if err == io.EOF {
						break
					}
					if err != nil {
						return c.Status(http.StatusInternalServerError).SendString("Failed to read file in zip")
					}
					text.Write(buf[:n])
				}
			}
		}

		// Return the concatenated text
		return c.SendString(text.String())
	})

	log.Fatal(app.Listen(":5000"))
}

